   1→/*
   2→ * Todo List Application -- Main Stylesheet
   3→ *
   4→ * CSS Architecture: Cascade Layers
   5→ * ---------------------------------
   6→ * Layers control specificity order regardless of source order.
   7→ * Earlier layers have lower priority; later layers win ties.
   8→ *
   9→ * @layer reset     -- Normalize browser defaults
  10→ * @layer tokens    -- Design tokens (CSS custom properties on :root)
  11→ * @layer base      -- Element-level styles (body, headings, links, forms)
  12→ * @layer layout    -- Page-level layout (CSS Grid, containers)
  13→ * @layer components -- Component-specific styles (added per feature)
  14→ * @layer utilities -- Helper classes (visually-hidden, etc.)
  15→ */
  16→
  17→@layer reset, tokens, base, layout, components, utilities;
  18→
  19→/* ==========================================================================
  20→   RESET LAYER
  21→   Modern CSS reset. Removes browser inconsistencies while preserving
  22→   useful defaults. Based on Andy Bell's modern reset.
  23→   ========================================================================== */
  24→
  25→@layer reset {
  26→  *,
  27→  *::before,
  28→  *::after {
  29→    box-sizing: border-box;
  30→  }
  31→
  32→  * {
  33→    margin: 0;
  34→    padding: 0;
  35→  }
  36→
  37→  html {
  38→    -moz-text-size-adjust: none;
  39→    -webkit-text-size-adjust: none;
  40→    text-size-adjust: none;
  41→  }
  42→
  43→  body {
  44→    min-block-size: 100vh;
  45→    line-height: 1.5;
  46→    -webkit-font-smoothing: antialiased;
  47→  }
  48→
  49→  img,
  50→  picture,
  51→  video,
  52→  canvas,
  53→  svg {
  54→    display: block;
  55→    max-inline-size: 100%;
  56→  }
  57→
  58→  input,
  59→  button,
  60→  textarea,
  61→  select {
  62→    font: inherit;
  63→    color: inherit;
  64→  }
  65→
  66→  p,
  67→  h1,
  68→  h2,
  69→  h3,
  70→  h4,
  71→  h5,
  72→  h6 {
  73→    overflow-wrap: break-word;
  74→  }
  75→
  76→  h1,
  77→  h2,
  78→  h3,
  79→  h4,
  80→  h5,
  81→  h6 {
  82→    text-wrap: balance;
  83→  }
  84→
  85→  a {
  86→    color: inherit;
  87→    text-decoration-skip-ink: auto;
  88→  }
  89→
  90→  ul[role="list"],
  91→  ol[role="list"] {
  92→    list-style: none;
  93→  }
  94→
  95→  /* Remove default button styles */
  96→  button {
  97→    cursor: pointer;
  98→    background: none;
  99→    border: none;
 100→  }
 101→
 102→  /* Remove animations and transitions for users who prefer reduced motion */
 103→  @media (prefers-reduced-motion: reduce) {
 104→    *,
 105→    *::before,
 106→    *::after {
 107→      animation-duration: 0.01ms !important;
 108→      animation-iteration-count: 1 !important;
 109→      transition-duration: 0.01ms !important;
 110→      scroll-behavior: auto !important;
 111→    }
 112→  }
 113→}
 114→
 115→/* ==========================================================================
 116→   TOKENS LAYER
 117→   Design tokens as CSS custom properties on :root.
 118→
 119→   Token system:
 120→   - Spacing:    4px base unit, named --space-xs through --space-3xl
 121→   - Colors:     oklch color space for perceptual uniformity
 122→   - Typography: System font stack, fluid type scale with clamp()
 123→   - Shadows:    Three levels (sm, md, lg)
 124→   - Radii:      Three sizes (sm, md, lg)
 125→   - Transitions: Duration values for consistent animation timing
 126→
 127→   All component styles reference tokens -- no hardcoded values.
 128→   Token changes go through the mob with Steve Schoger's approval.
 129→   ========================================================================== */
 130→
 131→@layer tokens {
 132→  :root {
 133→    /* ---- Spacing Scale ----
 134→     * 4px base unit. Numbered primitives map to multiples of 4px.
 135→     * Semantic aliases below provide meaningful names for common uses.
 136→     * Scale: 4, 8, 12, 16, 24, 32, 48, 64, 96
 137→     */
 138→    --space-1:  0.25rem;  /* 4px */
 139→    --space-2:  0.5rem;   /* 8px */
 140→    --space-3:  0.75rem;  /* 12px */
 141→    --space-4:  1rem;     /* 16px */
 142→    --space-6:  1.5rem;   /* 24px */
 143→    --space-8:  2rem;     /* 32px */
 144→    --space-12: 3rem;     /* 48px */
 145→    --space-16: 4rem;     /* 64px */
 146→    --space-24: 6rem;     /* 96px */
 147→
 148→    /* Semantic spacing aliases */
 149→    --space-xs:  var(--space-1);   /* 4px */
 150→    --space-sm:  var(--space-2);   /* 8px */
 151→    --space-md:  var(--space-4);   /* 16px */
 152→    --space-lg:  var(--space-6);   /* 24px */
 153→    --space-xl:  var(--space-8);   /* 32px */
 154→    --space-2xl: var(--space-12);  /* 48px */
 155→    --space-3xl: var(--space-16);  /* 64px */
 156→
 157→    /* ---- Color Palette ----
 158→     * oklch color space for perceptual uniformity.
 159→     * Most UI is grayscale; color is for emphasis and interaction.
 160→     * "The grays do the heavy lifting, primary blue is supporting cast."
 161→     *
 162→     * oklch(Lightness Chroma Hue)
 163→     * - Lightness: 0 (black) to 1 (white)
 164→     * - Chroma: 0 (gray) to ~0.4 (most saturated)
 165→     * - Hue: 0-360 degrees
 166→     */
 167→
 168→    /* Neutral grays -- zero chroma for true neutrals
 169→     *
 170→     * Contrast ratios vs white (#fff):
 171→     *   gray-50 to gray-300: decorative/border use only, NOT for text
 172→     *   gray-400 (~0.71): ~3:1  -- large text/UI components minimum
 173→     *   gray-500 (~0.55): ~4.6:1 -- normal text AA (borderline)
 174→     *   gray-600 (~0.45): ~7:1  -- normal text AA, comfortable
 175→     *   gray-700+:         ~10:1+ -- high contrast
 176→     *
 177→     * For text on light backgrounds, use gray-500 or darker for AA. */
 178→    --color-gray-50:  oklch(0.985 0 0); /* near-white backgrounds */
 179→    --color-gray-100: oklch(0.97 0 0);  /* subtle backgrounds, hover states */
 180→    --color-gray-200: oklch(0.925 0 0); /* borders, dividers */
 181→    --color-gray-300: oklch(0.87 0 0);  /* disabled text, emphasized borders */
 182→    --color-gray-400: oklch(0.71 0 0);  /* muted text (large only), icons */
 183→    --color-gray-500: oklch(0.55 0 0);  /* secondary text */
 184→    --color-gray-600: oklch(0.45 0 0);  /* body text */
 185→    --color-gray-700: oklch(0.37 0 0);  /* strong text */
 186→    --color-gray-800: oklch(0.27 0 0);  /* headings */
 187→    --color-gray-900: oklch(0.18 0 0);  /* near-black, high emphasis */
 188→
 189→    /* Primary -- blue for interactive elements.
 190→     * One blue. Used for links, buttons, focus rings. That's it.
 191→     * Hue 240, moderate chroma for a professional look. */
 192→    --color-primary-light: oklch(0.75 0.1 240);  /* hover states, light badges */
 193→    --color-primary:       oklch(0.52 0.18 240);  /* buttons, links, active states */
 194→    --color-primary-dark:  oklch(0.42 0.18 240);  /* pressed states, dark accents */
 195→
 196→    /* Semantic colors
 197→     * IMPORTANT: Color must never be the sole indicator of state.
 198→     * Every use of danger/success/warning must be paired with a
 199→     * secondary visual cue: icon, text label, strikethrough, border
 200→     * style change, etc. This is a WCAG requirement and team agreement. */
 201→    --color-danger:        oklch(0.55 0.2 25);   /* destructive actions, errors */
 202→    --color-danger-light:  oklch(0.92 0.04 25);  /* danger backgrounds */
 203→    --color-success:       oklch(0.6 0.17 145);  /* icons/indicators only -- ~3.9:1, fails AA for normal text */
 204→    --color-success-light: oklch(0.92 0.04 145); /* success backgrounds */
 205→    --color-warning:       oklch(0.75 0.15 75);  /* warnings */
 206→    --color-warning-light: oklch(0.93 0.04 75);  /* warning backgrounds */
 207→
 208→    /* Foreground / background semantic tokens */
 209→    --color-bg:            var(--color-gray-50);   /* page background */
 210→    --color-bg-raised:     white;                  /* cards, raised surfaces */
 211→    --color-fg:            var(--color-gray-800);  /* primary text */
 212→    --color-fg-muted:      var(--color-gray-600);  /* secondary text (~7.4:1 vs white -- comfortable AA for all text sizes) */
 213→    --color-fg-subtle:     var(--color-gray-400);  /* placeholders, hint text (3:1 -- NOT for body text) */
 214→    --color-border:        var(--color-gray-200);  /* default borders */
 215→    --color-border-strong: var(--color-gray-300);  /* emphasized borders, input focus */
 216→
 217→    /* ---- Typography ----
 218→     * System font stack -- no web font downloads, instant rendering.
 219→     * Fluid type scale using clamp() for smooth scaling between
 220→     * viewport sizes. Min at ~320px, max at ~1200px.
 221→     */
 222→    --font-sans: system-ui, -apple-system, "Segoe UI", Roboto,
 223→      "Helvetica Neue", Arial, sans-serif;
 224→
 225→    --font-mono: ui-monospace, "Cascadia Code", "Source Code Pro",
 226→      Menlo, Consolas, "DejaVu Sans Mono", monospace;
 227→
 228→    /* Fluid type scale
 229→     * clamp(min, preferred, max)
 230→     * Preferred uses viewport units for smooth scaling */
 231→    --font-size-xs:   clamp(0.6875rem, 0.65rem + 0.1vw, 0.75rem);     /* ~11-12px, fine print */
 232→    --font-size-sm:   clamp(0.8125rem, 0.78rem + 0.1vw, 0.875rem);    /* ~13-14px, captions */
 233→    --font-size-base: clamp(0.9375rem, 0.9rem + 0.12vw, 1rem);        /* ~15-16px, body text */
 234→    --font-size-lg:   clamp(1.0625rem, 1rem + 0.15vw, 1.125rem);      /* ~17-18px, subheadings */
 235→    --font-size-xl:   clamp(1.1875rem, 1.1rem + 0.2vw, 1.3125rem);    /* ~19-21px, section headings */
 236→    --font-size-2xl:  clamp(1.4375rem, 1.3rem + 0.3vw, 1.625rem);     /* ~23-26px, page headings */
 237→    --font-size-3xl:  clamp(1.75rem, 1.6rem + 0.4vw, 2.125rem);       /* ~28-34px, hero/display */
 238→
 239→    /* Line heights */
 240→    --leading-tight:   1.25;   /* headings */
 241→    --leading-snug:    1.375;  /* subheadings, large text */
 242→    --leading-normal:  1.5;    /* body text */
 243→    --leading-relaxed: 1.625;  /* small text that needs more air */
 244→
 245→    /* Font weights */
 246→    --font-normal:    400;
 247→    --font-medium:    500;
 248→    --font-semibold:  600;
 249→    --font-bold:      700;
 250→
 251→    /* ---- Shadows ----
 252→     * Three levels. Shadows use oklch for consistency with the color system.
 253→     * Never combine shadows and borders on the same element (per team agreement).
 254→     */
 255→    --shadow-sm:  0 1px 2px oklch(0.18 0 0 / 0.05);
 256→    --shadow-md:  0 4px 6px -1px oklch(0.18 0 0 / 0.07),
 257→                  0 2px 4px -2px oklch(0.18 0 0 / 0.05);
 258→    --shadow-lg:  0 10px 15px -3px oklch(0.18 0 0 / 0.08),
 259→                  0 4px 6px -4px oklch(0.18 0 0 / 0.04);
 260→
 261→    /* ---- Border Radius ---- */
 262→    --radius-sm:   0.25rem;  /* 4px -- badges, tags */
 263→    --radius-md:   0.5rem;   /* 8px -- buttons, inputs, cards */
 264→    --radius-lg:   0.75rem;  /* 12px -- larger containers, modals */
 265→    --radius-full: 9999px;   /* pills, avatars */
 266→
 267→    /* ---- Transition Durations ----
 268→     * Motion-safe by default: tokens are 0s unless the user has no
 269→     * motion preference. This means developers can use transition
 270→     * tokens without needing to remember the media query wrapper --
 271→     * the tokens themselves are inert when reduced motion is active.
 272→     * The reset layer catch-all (prefers-reduced-motion: reduce) is
 273→     * a secondary safety net.
 274→     * Easing: ease (not ease-in-out).
 275→     */
 276→    --transition-fast:   0s;
 277→    --transition-normal: 0s;
 278→    --transition-slow:   0s;
 279→
 280→    /* ---- Focus Ring ----
 281→     * Reusable focus ring properties for consistent :focus-visible styles.
 282→     * 3:1+ contrast against background (blue on white/light gray).
 283→     */
 284→    --focus-ring-color:  var(--color-primary);
 285→    --focus-ring-offset: 2px;
 286→    --focus-ring-width:  2px;
 287→  }
 288→
 289→  /* Activate transition durations only when user has no motion preference */
 290→  @media (prefers-reduced-motion: no-preference) {
 291→    :root {
 292→      --transition-fast:   100ms;  /* micro-interactions: hover, focus */
 293→      --transition-normal: 200ms;  /* standard: expand, slide */
 294→      --transition-slow:   300ms;  /* larger: modal, page */
 295→    }
 296→  }
 297→}
 298→
 299→/* ==========================================================================
 300→   BASE LAYER
 301→   Element-level styles applied directly to HTML elements.
 302→   No classes -- this establishes the typographic and interactive baseline.
 303→   ========================================================================== */
 304→
 305→@layer base {
 306→  body {
 307→    font-family: var(--font-sans);
 308→    font-size: var(--font-size-base);
 309→    font-weight: var(--font-normal);
 310→    line-height: var(--leading-normal);
 311→    color: var(--color-fg);
 312→    background-color: var(--color-bg);
 313→  }
 314→
 315→  /* Headings -- tighter line-height, bolder weight, type scale */
 316→  h1 {
 317→    font-size: var(--font-size-3xl);
 318→    font-weight: var(--font-bold);
 319→    line-height: var(--leading-tight);
 320→  }
 321→
 322→  h2 {
 323→    font-size: var(--font-size-2xl);
 324→    font-weight: var(--font-bold);
 325→    line-height: var(--leading-tight);
 326→  }
 327→
 328→  h3 {
 329→    font-size: var(--font-size-xl);
 330→    font-weight: var(--font-semibold);
 331→    line-height: var(--leading-snug);
 332→  }
 333→
 334→  h4 {
 335→    font-size: var(--font-size-lg);
 336→    font-weight: var(--font-semibold);
 337→    line-height: var(--leading-snug);
 338→  }
 339→
 340→  h5,
 341→  h6 {
 342→    font-size: var(--font-size-base);
 343→    font-weight: var(--font-medium);
 344→    line-height: var(--leading-snug);
 345→  }
 346→
 347→  /* Links */
 348→  a {
 349→    color: var(--color-primary);
 350→    text-decoration: underline;
 351→    text-underline-offset: 0.15em;
 352→
 353→    &:hover {
 354→      color: var(--color-primary-dark);
 355→    }
 356→  }
 357→
 358→  /* Focus-visible styles for all interactive elements.
 359→   * Uses outline for keyboard focus, visible only on keyboard navigation.
 360→   * Double-ring technique: white inner ring (box-shadow) + colored outer ring
 361→   * (outline) ensures visibility on both light and dark backgrounds.
 362→   * 3:1+ contrast ratio maintained in all contexts. */
 363→  :focus-visible {
 364→    outline: var(--focus-ring-width) solid var(--focus-ring-color);
 365→    outline-offset: var(--focus-ring-offset);
 366→    box-shadow: 0 0 0 var(--focus-ring-offset) white;
 367→  }
 368→
 369→  /* Buttons -- base styles, ready for component overrides */
 370→  button,
 371→  [type="button"],
 372→  [type="submit"],
 373→  [type="reset"] {
 374→    display: inline-flex;
 375→    align-items: center;
 376→    justify-content: center;
 377→    gap: var(--space-sm);
 378→    padding-block: var(--space-sm);
 379→    padding-inline: var(--space-md);
 380→    font-size: var(--font-size-base);
 381→    font-weight: var(--font-medium);
 382→    line-height: var(--leading-tight);
 383→    border-radius: var(--radius-md);
 384→    background-color: var(--color-primary);
 385→    color: white;
 386→
 387→    &:hover {
 388→      background-color: var(--color-primary-dark);
 389→    }
 390→  }
 391→
 392→  @media (prefers-reduced-motion: no-preference) {
 393→    button,
 394→    [type="button"],
 395→    [type="submit"],
 396→    [type="reset"] {
 397→      transition: background-color var(--transition-fast) ease;
 398→    }
 399→  }
 400→
 401→  /* Form inputs */
 402→  input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
 403→  textarea,
 404→  select {
 405→    display: block;
 406→    inline-size: 100%;
 407→    padding-block: var(--space-sm);
 408→    padding-inline: var(--space-3);
 409→    font-size: var(--font-size-base);
 410→    line-height: var(--leading-normal);
 411→    color: var(--color-fg);
 412→    background-color: var(--color-bg-raised);
 413→    border: 1px solid var(--color-border);
 414→    border-radius: var(--radius-md);
 415→
 416→    &::placeholder {
 417→      color: var(--color-fg-subtle);
 418→    }
 419→  }
 420→
 421→  /* Invalid inputs -- danger border for any input with aria-invalid */
 422→  [aria-invalid="true"] {
 423→    border-color: var(--color-danger);
 424→  }
 425→
 426→  /* Labels */
 427→  label {
 428→    display: block;
 429→    font-size: var(--font-size-sm);
 430→    font-weight: var(--font-medium);
 431→    color: var(--color-fg);
 432→  }
 433→
 434→  /* Fieldset */
 435→  fieldset {
 436→    border: none;
 437→  }
 438→
 439→  /* Code */
 440→  code,
 441→  pre {
 442→    font-family: var(--font-mono);
 443→    font-size: var(--font-size-sm);
 444→  }
 445→
 446→  /* Windows High Contrast Mode support.
 447→   * In forced-colors mode, the browser overrides most colors.
 448→   * We ensure borders, outlines, and structural indicators remain
 449→   * visible since they become the primary way to distinguish elements. */
 450→  @media (forced-colors: active) {
 451→    button,
 452→    [type="button"],
 453→    [type="submit"],
 454→    [type="reset"] {
 455→      border: 1px solid ButtonText;
 456→    }
 457→
 458→    input:not([type="checkbox"]):not([type="radio"]):not([type="submit"]):not([type="button"]):not([type="reset"]),
 459→    textarea,
 460→    select {
 461→      border: 1px solid ButtonText;
 462→    }
 463→
 464→    :focus-visible {
 465→      outline: 2px solid Highlight;
 466→      outline-offset: 2px;
 467→    }
 468→  }
 469→}
 470→
 471→/* ==========================================================================
 472→   LAYOUT LAYER
 473→   Page-level layout using CSS Grid. Mobile-first, desktop breakpoint ~1024px.
 474→   Uses logical properties for RTL support.
 475→   ========================================================================== */
 476→
 477→@layer layout {
 478→  /* Page layout: header / main / footer with sticky footer */
 479→  .page-layout {
 480→    display: grid;
 481→    grid-template-rows: auto 1fr auto;
 482→    min-block-size: 100vh;
 483→  }
 484→
 485→  /* Constrained content container */
 486→  .container {
 487→    inline-size: 100%;
 488→    max-inline-size: 44rem; /* ~704px -- GTD nav needs more room */
 489→    margin-inline: auto;
 490→    padding-inline: var(--space-md);
 491→  }
 492→
 493→  /* Wider container variant for pages that need more space */
 494→  .container--wide {
 495→    max-inline-size: 64rem; /* ~1024px */
 496→  }
 497→
 498→  /* Responsive adjustments */
 499→  @media (min-width: 1024px) {
 500→    .container {
 501→      padding-inline: var(--space-lg);
 502→    }
 503→  }
 504→
 505→  /* Container query setup -- components can respond to their container */
 506→  .component-container {
 507→    container-type: inline-size;
 508→  }
 509→}
 510→
 511→/* ==========================================================================
 512→   COMPONENTS LAYER
 513→   Component-specific styles are added here as features are built.
 514→   Each component should be self-contained and reference only design tokens.
 515→   ========================================================================== */
 516→
 517→@layer components {
 518→  /* ---- HTMX Indicators ----
 519→   * .htmx-indicator elements are hidden by default and revealed when
 520→   * HTMX adds .htmx-request to a requesting element or its parent.
 521→   * Used for inline loading spinners/text during server requests.
 522→   * See: https://htmx.org/attributes/hx-indicator/ */
 523→  .htmx-indicator {
 524→    opacity: 0;
 525→    transition: opacity var(--transition-normal) ease;
 526→  }
 527→
 528→  .htmx-request .htmx-indicator,
 529→  .htmx-request.htmx-indicator {
 530→    opacity: 1;
 531→  }
 532→
 533→  /* ---- Auth Form ----
 534→   * Used for registration, login, and similar auth-related forms.
 535→   * Centered, constrained-width form with vertical field stacking. */
 536→  .auth-form {
 537→    max-inline-size: 24rem;
 538→    margin-inline: auto;
 539→    padding-block-start: var(--space-2xl);
 540→  }
 541→
 542→  .auth-form h1 {
 543→    margin-block-end: var(--space-lg);
 544→  }
 545→
 546→  .auth-form__fields {
 547→    display: flex;
 548→    flex-direction: column;
 549→    gap: var(--space-lg);
 550→  }
 551→
 552→  .auth-form__group {
 553→    display: flex;
 554→    flex-direction: column;
 555→    gap: var(--space-xs);
 556→  }
 557→
 558→
 559→  .auth-form__error {
 560→    color: var(--color-danger);
 561→    font-size: var(--font-size-sm);
 562→  }
 563→
 564→  .auth-form__hint {
 565→    font-size: var(--font-size-xs);
 566→    color: var(--color-fg-muted);
 567→  }
 568→
 569→  /* Password visibility toggle -- JS progressive enhancement */
 570→  .password-toggle {
 571→    background: none;
 572→    border: none;
 573→    padding: 0;
 574→    border-radius: 0;
 575→    color: var(--color-primary);
 576→    font-size: var(--font-size-xs);
 577→    font-weight: var(--font-normal);
 578→    cursor: pointer;
 579→    text-decoration: underline;
 580→    text-underline-offset: 0.15em;
 581→  }
 582→
 583→  .password-toggle:hover {
 584→    background: none;
 585→    color: var(--color-primary-dark);
 586→  }
 587→
 588→  .auth-form__message {
 589→    padding: var(--space-sm) var(--space-md);
 590→    border-radius: var(--radius-md);
 591→    font-size: var(--font-size-sm);
 592→    margin-block-end: var(--space-lg);
 593→  }
 594→
 595→  /* Collapse empty message containers so they don't leave a gap */
 596→  .auth-form__message:empty {
 597→    display: none;
 598→  }
 599→
 600→  .auth-form__message--error {
 601→    background-color: var(--color-danger-light);
 602→    color: var(--color-danger);
 603→  }
 604→
 605→  .auth-form__submit {
 606→    inline-size: 100%;
 607→  }
 608→
 609→  /* Actions row (save + cancel) for edit forms */
 610→  .auth-form__actions {
 611→    display: flex;
 612→    align-items: center;
 613→    gap: var(--space-md);
 614→  }
 615→
 616→  /* Cancel link styled as secondary text action */
 617→  .auth-form__cancel {
 618→    font-size: var(--font-size-sm);
 619→    color: var(--color-fg-muted);
 620→  }
 621→
 622→  .auth-form__cancel:hover {
 623→    color: var(--color-fg);
 624→  }
 625→
 626→  .auth-form__footer {
 627→    margin-block-start: var(--space-lg);
 628→    text-align: center;
 629→    font-size: var(--font-size-sm);
 630→    color: var(--color-fg-muted);
 631→  }
 632→
 633→  /* ---- Site Header ----
 634→   * Authenticated page header with brand link and user actions (logout).
 635→   * Flexbox layout: brand left, actions right. */
 636→  .site-header {
 637→    display: flex;
 638→    align-items: center;
 639→    justify-content: space-between;
 640→    padding-block: var(--space-md);
 641→  }
 642→
 643→  .site-header__brand {
 644→    font-weight: var(--font-semibold);
 645→    color: var(--color-fg);
 646→    text-decoration: none;
 647→  }
 648→
 649→  .site-header__actions {
 650→    display: flex;
 651→    align-items: center;
 652→    gap: var(--space-md);
 653→    font-size: var(--font-size-sm);
 654→    color: var(--color-fg-muted);
 655→  }
 656→
 657→  /* ---- Text Button ----
 658→   * Button styled as a text link. Used for logout and other
