 773→  }
 774→
 775→  /* Restore border in forced-colors mode since the base layer's
 776→   * button border: none is overridden by components, but forced-colors
 777→   * needs an explicit border to make the toggle visible. */
 778→  @media (forced-colors: active) {
 779→    .todo-item__toggle {
