 856→  /* ---- Edit Mode ----
 857→   * Pencil icon button triggers edit mode (US-8). No-JS baseline
 858→   * navigates to an edit page; HTMX swaps inline. */
 859→  .todo-item__edit {
 860→    background: none;
 861→    border: none;
 862→    padding: var(--space-xs);
 863→    cursor: pointer;
 864→    color: var(--color-fg-muted);
 865→    font-size: var(--font-size-sm);
 866→    flex-shrink: 0;
 867→  }
 868→
 869→  .todo-item__edit:hover {
 870→    color: var(--color-primary);
 871→  }
 872→
 873→  /* Edit form replaces the title when in edit mode */
 874→  .todo-item__edit-form {
 875→    flex: 1;
 876→    display: flex;
 877→    align-items: center;
 878→    gap: var(--space-xs);
 879→    min-inline-size: 0;
 880→  }
 881→
 882→  .todo-item__edit-input {
